import { ref, onMounted } from 'vue'
import profile from '@/api/profile'
import { ElMessage } from 'element-plus'

export function useModules() {
  const loading = ref(false)
  const activeModules = ref([])
  const inactiveModules = ref([])
  const moduleData = ref({})

  // 初始化模块配置
  const initModules = () => {
    // 定义所有可能的模块
    const allModules = [
      { type: 'basic_info', name: '基本信息', visible: true, order: 1 },
      { type: 'job_intention', name: '求职意向', visible: true, order: 2 },
      { type: 'work_experience', name: '工作经历', visible: true, order: 3 },
      { type: 'education', name: '教育经历', visible: true, order: 4 },
      { type: 'project', name: '项目经历', visible: true, order: 5 },
      { type: 'skill', name: '专业技能', visible: true, order: 6 },
      { type: 'certificate', name: '证书奖项', visible: true, order: 7 },
      { type: 'language', name: '语言能力', visible: true, order: 8 },
      { type: 'portfolio', name: '作品展示', visible: true, order: 9 },
      { type: 'social_link', name: '社交主页', visible: true, order: 10 }
    ]

    // 初始化激活的模块
    activeModules.value = allModules
  }

  // 获取布局配置
  const fetchLayout = async () => {
    try {
      const response = await profile.getLayout()
      if (response.data?.code === 200) {
        const layout = response.data.data

        // 更新模块的可见性和排序
        activeModules.value = activeModules.value.map(module => ({
          ...module,
          visible: layout[module.type]?.visible ?? true,
          order: layout[module.type]?.order ?? module.order
        }))

        // 根据可见性分类
        const { active, inactive } = activeModules.value.reduce((acc, module) => {
          if (module.visible) {
            acc.active.push(module)
          } else {
            acc.inactive.push(module)
          }
          return acc
        }, { active: [], inactive: [] })

        // 根据 order 排序
        activeModules.value = active.sort((a, b) => a.order - b.order)
        inactiveModules.value = inactive.sort((a, b) => a.order - b.order)

        console.log('布局配置更新:', {
          活动模块: activeModules.value,
          未激活模块: inactiveModules.value
        })
      }
    } catch (error) {
      console.error('获取布局配置失败:', error)
      ElMessage.error('获取布局配置失败')
    }
  }

  // 更新布局配置
  const updateLayout = async (updates) => {
    try {
      loading.value = true
      const response = await profile.updateLayout(updates)

      if (response.data?.code === 200) {
        // 重新获取布局配置
        await fetchLayout()
        return response.data
      }
    } catch (error) {
      console.error('更新布局失败:', error)
      throw error
    } finally {
      loading.value = false
    }
  }

  // 获取所有模块数据
  const fetchModulesData = async () => {
    try {
      loading.value = true
      console.log('开始获取档案数据')

      // 确保模块配置已初始化
      if (activeModules.value.length === 0) {
        initModules()
      }

      // 获取布局配置
      await fetchLayout()

      const response = await profile.getData()
      console.log('档案数据响应:', response)

      if (response.data?.code === 200) {
        const data = response.data.data

        // 更新各模块数据
        moduleData.value = {
          basic_info: data.basic_info || null,
          job_intention: data.job_intention || null,
          work_experience: data.work_experience || [],
          education: data.education || [],
          project: data.project || [],
          skill: data.skill || [],
          certificate: data.certificate || [],
          language: data.language || [],
          portfolio: data.portfolio || [],
          social_link: data.social_link || []
        }

        // 更新模块显示状态
        activeModules.value = activeModules.value.map(module => ({
          ...module,
          data: moduleData.value[module.type]
        }))

        console.log('获取档案数据成功:', {
          模块数据: moduleData.value,
          活动模块: activeModules.value
        })
      }
    } catch (error) {
      console.error('获取档案数据失败:', error)
      ElMessage.error('获取数据失败，请刷新重试')
    } finally {
      loading.value = false
    }
  }

  // 更新模块数据
  const updateModuleData = async (type, data) => {
    try {
      loading.value = true
      const response = await profile.updateModule(type, data)

      if (response.data?.code === 200) {
        // 更新本地数据
        moduleData.value[type] = response.data.data

        // 更新模块显示
        const module = activeModules.value.find(m => m.type === type)
        if (module) {
          module.data = response.data.data
        }

        return response.data.data
      }
    } catch (error) {
      console.error('更新模块数据失败:', error)
      throw error
    } finally {
      loading.value = false
    }
  }

  // 添加模块项目
  const addModuleItem = async (type, data) => {
    try {
      loading.value = true
      const response = await profile.addModuleItem(type, data)

      if (response.data?.code === 200) {
        // 重新获取最新数据
        await fetchModulesData()
        return response.data.data
      }
    } catch (error) {
      console.error('添加模块项目失败:', error)
      throw error
    } finally {
      loading.value = false
    }
  }

  // 删除模块项目
  const deleteModuleItem = async (type, id) => {
    try {
      loading.value = true
      await profile.deleteModuleItem(type, id)
      // 重新获取最新数据
      await fetchModulesData()
    } catch (error) {
      console.error('删除模块项目失败:', error)
      throw error
    } finally {
      loading.value = false
    }
  }

  // 初始化
  onMounted(() => {
    initModules()
  })

  return {
    loading,
    activeModules,
    inactiveModules,
    moduleData,
    fetchModulesData,
    updateModuleData,
    addModuleItem,
    deleteModuleItem,
    updateLayout,
    fetchLayout
  }
}
